const initTabs=()=>{document.querySelectorAll("[data-tabs]").forEach(t=>{const e=t.querySelectorAll("[data-tabs-trigger]"),s=t.querySelectorAll("[data-tabs-panel]");e.forEach(a=>{a.addEventListener("click",()=>{const i=a.dataset.tab;e.forEach(t=>{t.classList.toggle("is-active",t===a),t.setAttribute("aria-selected",t===a?"true":"false")}),s.forEach(t=>{const e=t.dataset.tab===i;t.classList.toggle("is-active",e),t.hidden=!e}),t.dispatchEvent(new CustomEvent("tabs:change",{detail:{tab:i},bubbles:!0}))})})})};function initTooltips(){document.querySelectorAll("[data-tooltip]").forEach(t=>{t.classList.add("tooltip-wrapper");const e=t.dataset.tooltip,s=document.createElement("span");s.className="tooltip-bubble",s.textContent=e,t.appendChild(s),t.addEventListener("mouseenter",()=>s.classList.add("is-visible")),t.addEventListener("mouseleave",()=>s.classList.remove("is-visible")),t.addEventListener("focusin",()=>s.classList.add("is-visible")),t.addEventListener("focusout",()=>s.classList.remove("is-visible"))})}document.addEventListener("DOMContentLoaded",()=>{initTabs(),initTooltips()});